function kForce(nodes, edges, W, H) {
  // semantic clustering force layout (clusters by type), pure function of the data
  const types = [...new Set(nodes.map((n) => n.type))];
  const anchor = {};
  types.forEach((t, i) => {
    const ang = (2 * Math.PI * i) / types.length;
    anchor[t] = { x: W / 2 + Math.cos(ang) * W * 0.3, y: H / 2 + Math.sin(ang) * H * 0.3 };
  });
  const N = nodes.map((n) => ({ id: n.id, t: n.type, x: anchor[n.type].x + (Math.random() - 0.5) * 80, y: anchor[n.type].y + (Math.random() - 0.5) * 80 }));
  const pos = Object.fromEntries(N.map((n) => [n.id, n]));
  const E = edges.filter(([a, b]) => pos[a] && pos[b]);
  for (let it = 0; it < 300; it++) {
    for (let i = 0; i < N.length; i++)
      for (let j = i + 1; j < N.length; j++) {
        const a = N[i], b = N[j];
        let dx = a.x - b.x, dy = a.y - b.y, d2 = dx * dx + dy * dy || 1, d = Math.sqrt(d2);
        const f = Math.min(3400 / d2, 7); dx /= d; dy /= d; a.x += dx * f; a.y += dy * f; b.x -= dx * f; b.y -= dy * f;
      }
    E.forEach(([s, t]) => {
      const a = pos[s], b = pos[t]; let dx = b.x - a.x, dy = b.y - a.y, d = Math.sqrt(dx * dx + dy * dy) || 1;
      const f = (d - 96) * 0.016; dx /= d; dy /= d; a.x += dx * f; a.y += dy * f; b.x -= dx * f; b.y -= dy * f;
    });
    N.forEach((n) => {
      const an = anchor[n.t]; n.x += (an.x - n.x) * 0.014; n.y += (an.y - n.y) * 0.014;
      n.x = Math.max(54, Math.min(W - 54, n.x)); n.y = Math.max(34, Math.min(H - 34, n.y));
    });
  }
  return pos;
}

function ExploreGraph({ sel, setSel, focusType, setFocusType }) {
  const W = 760, H = 520;
  const shown = useMemo(
    () => (focusType === "all" ? KNODES : KNODES.filter((n) => n.type === focusType || (sel && (n.id === sel)))),
    [focusType, sel]
  );
  const ids = new Set(shown.map((n) => n.id));
  const edges = useMemo(() => KEDGES.filter(([a, b]) => ids.has(a) && ids.has(b)), [focusType, sel]);
  const pos = useMemo(() => kForce(shown, edges, W, H), [focusType, sel]);
  const [vp, setVp] = useState({ x: 0, y: 0, k: 1 });
  const drag = useRef(null);
  const onWheel = (e) => { e.preventDefault(); setVp((v) => ({ ...v, k: Math.max(0.4, Math.min(2.4, v.k * (e.deltaY < 0 ? 1.12 : 0.89))) })); };
  const onDown = (e) => { drag.current = { sx: e.clientX, sy: e.clientY, ox: vp.x, oy: vp.y }; };
  const onMove = (e) => { if (!drag.current) return; setVp((v) => ({ ...v, x: drag.current.ox + e.clientX - drag.current.sx, y: drag.current.oy + e.clientY - drag.current.sy })); };
  const onUp = () => { drag.current = null; };
  const neigh = new Set();
  if (sel) KEDGES.forEach(([a, b]) => { if (a === sel) neigh.add(b); if (b === sel) neigh.add(a); });
  return (
    <div className="afp-gwrap">
      <svg viewBox={`0 0 ${W} ${H}`} className="afp-graph" onWheel={onWheel} onMouseDown={onDown} onMouseMove={onMove} onMouseUp={onUp} onMouseLeave={onUp}>
        <g transform={`translate(${vp.x},${vp.y}) scale(${vp.k})`}>
          {edges.map(([a, b, rel], i) => {
            if (!pos[a] || !pos[b]) return null;
            const hot = sel && (a === sel || b === sel);
            const mx = (pos[a].x + pos[b].x) / 2, my = (pos[a].y + pos[b].y) / 2;
            return (
              <g key={i}>
                <line x1={pos[a].x} y1={pos[a].y} x2={pos[b].x} y2={pos[b].y} stroke={hot ? "var(--cyan)" : "var(--line)"} strokeWidth={hot ? 1.6 : 1} strokeOpacity={sel && !hot ? 0.25 : 0.7} />
                {hot && <text x={mx} y={my - 3} textAnchor="middle" className="afp-gedge">{rel}</text>}
              </g>
            );
          })}
          {shown.map((n) => {
            const p = pos[n.id]; if (!p) return null;
            const isSel = sel === n.id, isNeigh = neigh.has(n.id);
            const dim = sel && !isSel && !isNeigh;
            const r = isSel ? 9 : 6.5;
            return (
              <g key={n.id} className="afp-gnode" transform={`translate(${p.x},${p.y})`} onClick={() => setSel(isSel ? null : n.id)} opacity={dim ? 0.35 : 1}>
                <circle r={r} fill={KTYPES[n.type].color} stroke={isSel ? "#fff" : "rgba(0,0,0,.4)"} strokeWidth={isSel ? 2 : 1} />
                <text x={r + 4} y={3.5} className="afp-gtext" fontWeight={isSel ? 600 : 400}>{n.label}</text>
              </g>
            );
          })}
        </g>
      </svg>
      <div className="afp-glegend">
        {Object.entries(KTYPES).map(([k, v]) => (
          <button key={k} className={"afp-gleg" + (focusType === k ? " on" : "")} onClick={() => { setSel(null); setFocusType(focusType === k ? "all" : k); }}>
            <span className="dot" style={{ background: v.color }} />{v.label}
          </button>
        ))}
        <span className="afp-ghint">drag · scroll to zoom · click a node · click a type to isolate</span>
      </div>
    </div>
  );
}

function ExploreHierarchy({ sel, setSel }) {
  const groups = {};
  KNODES.forEach((n) => { (groups[n.group] = groups[n.group] || []).push(n); });
  const ORDER = ["Reasoning spine", "Knowledge graph", "Cross-cutting", "Vendored foundation", "Delivery skills", "Support skills", "Tooling", "Veto-holders", "Templates"];
  const keys = Object.keys(groups).sort((a, b) => (ORDER.indexOf(a) + 1 || 99) - (ORDER.indexOf(b) + 1 || 99));
  return (
    <div className="afp-htree">
      {keys.map((g) => (
        <div className="afp-hgroup" key={g}>
          <div className="afp-hgroup-t">{g}<span className="afp-hcount">{groups[g].length}</span></div>
          <div className="afp-hitems">
            {groups[g].map((n) => (
              <button key={n.id} className={"afp-hitem" + (sel === n.id ? " on" : "")} onClick={() => setSel(sel === n.id ? null : n.id)}>
                <span className="dot" style={{ background: KTYPES[n.type].color }} />{n.label}
              </button>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

function ExploreDetail({ sel, setSel }) {
  const n = sel && K_BY_ID[sel];
  if (!n) return (
    <div className="afp-kdetail afp-kempty">
      Select any node — in the hierarchy or the graph — to see what it is and how it connects.
      <span>The hierarchy groups the pack by role; the graph shows the typed relationships. They are two views of one knowledge graph.</span>
    </div>
  );
  const out = KEDGES.filter(([a]) => a === sel).map(([, b, rel]) => [b, rel, K_BY_ID[b] ? K_BY_ID[b].label : b]);
  const back = K_BACK[sel] || [];
  const backRels = KEDGES.filter(([, b]) => b === sel).map(([a, , rel]) => [a, rel, K_BY_ID[a] ? K_BY_ID[a].label : a]);
  return (
    <div className="afp-kdetail">
      <div className="afp-ktype" style={{ color: KTYPES[n.type].color }}>{KTYPES[n.type].label} · {n.group}</div>
      <h3 className="afp-ktitle">{n.label}</h3>
      <p className="afp-kbody">{n.detail}</p>
      {out.length > 0 && (
        <div className="afp-klinks"><div className="afp-klabel">Connects to</div>
          {out.map(([to, rel, lbl], i) => (
            <button key={i} className="afp-klink" onClick={() => setSel(to)}><span className="rel">{rel} →</span>{lbl}</button>
          ))}
        </div>
      )}
      {backRels.length > 0 && (
        <div className="afp-klinks"><div className="afp-klabel">Referenced by</div>
          {backRels.map(([from, rel, lbl], i) => (
            <button key={i} className="afp-klink" onClick={() => setSel(from)}><span className="rel">← {rel}</span>{lbl}</button>
          ))}
        </div>
      )}
    </div>
  );
}

