export default function Overview() {
  const [tab, setTab] = useState("install");
  const [kview, setKview] = useState("graph");
  const [ksel, setKsel] = useState(null);
  const [kfocus, setKfocus] = useState("all");
  const [open, setOpen] = useState("specify");
  const [done, setDone] = useState(false);

  const sizeKB = PACK_B64 && PACK_B64.indexOf("_") === -1 ? Math.round((PACK_B64.length * 3) / 4 / 1024) : 0;

  function download() {
    try {
      const bytes = Uint8Array.from(atob(PACK_B64), (c) => c.charCodeAt(0));
      const url = URL.createObjectURL(new Blob([bytes], { type: "application/zip" }));
      const a = document.createElement("a");
      a.href = url; a.download = "ai-forward-pack.zip";
      document.body.appendChild(a); a.click(); a.remove();
      setTimeout(() => URL.revokeObjectURL(url), 4000);
      setDone(true); setTimeout(() => setDone(false), 2400);
    } catch (e) { alert("Download failed: " + (e && e.message ? e.message : e)); }
  }

  const DownloadBtn = ({ big }) => (
    <button className={"afp-cta" + (done ? " done" : "")} onClick={download}
      style={big ? { fontSize: 16, padding: "16px 26px" } : undefined}>
      {done ? <Check size={18} /> : <Download size={18} />}
      {done ? "Downloaded — ai-forward-pack.zip" : "Download the AI-Forward Pack"}
    </button>
  );

  return (
    <div className="afp-root">
      <style>{css}</style>
      <div className="afp-wrap">

        <header className="afp-head afp-in">
          <div style={{ flex: "1 1 420px" }}>
            <p className="afp-kicker">AI-Forward Pack · documentation overview</p>
            <h1 className="afp-h1">Drop it in, see what's<br />inside, run the skills.</h1>
            <p className="afp-sub">A repo-droppable extension to the Agent Knowledge Pack: collaborating peers that author, adversarial personas that attack, and a staged reasoning discipline — for Claude Code &amp; GitHub Copilot.</p>
          </div>
          <div className="afp-dl">
            <DownloadBtn />
            <span className="afp-dl-note">self-contained {sizeKB ? <>· <b>~{sizeKB} KB</b> .zip embedded</> : "· .zip embedded"} · rev <b>{PACK_SNAPSHOT.revision}</b> ({PACK_SNAPSHOT.bundle}) · no internet needed</span>
          </div>
        </header>

        <nav className="afp-tabs afp-in" style={{ animationDelay: ".06s" }}>
          {[["install", "1 · Drop it in"], ["contents", "2 · What's inside"], ["skills", "3 · Use the skills"], ["explore", "4 · Explore the knowledge"]].map(([id, label]) => (
            <button key={id} className={"afp-tab" + (tab === id ? " on" : "")} onClick={() => setTab(id)}>{label}</button>
          ))}
        </nav>

        {tab === "install" && (
          <section className="afp-in">
            <p className="afp-sect-t">Manual reconciliation — no installer</p>
            <p className="afp-hint" style={{ marginTop: 0 }}>The pack is plain text; you copy each source to its mapped destination. The full deployment map, the Copilot frontmatter wrap, and the update procedure live in <code>adapters/INSTALL.md</code>.</p>

            <p className="afp-sect-t" style={{ marginTop: 26 }}>The deployment map (summary)</p>
            <table className="afp-tbl"><tbody>
              {RECON.map(([f, d]) => (<tr key={f}><td>{f}</td><td>{d}</td></tr>))}
            </tbody></table>

            <p className="afp-sect-t" style={{ marginTop: 30 }}>What lands in your repo</p>
            <div className="afp-tree">{`<repo>/
├─ `}<b>CLAUDE.md</b>{` / `}<b>AGENTS.md</b>{`        `}<i># paste the managed blocks from adapters/managed-blocks/</i>{`
├─ `}<b>.claude/</b>{`  knowledge · skills · agents       `}<i># Claude Code</i>{`
├─ `}<b>.github/</b>{`  instructions · prompts · agents   `}<i># GitHub Copilot</i>{`
├─ `}<b>docs/index.html</b>{`  + docs-index.js            `}<i># the Docs Explorer (index created by the first skill run)</i>{`
└─ `}<b>docs/ai-forward-pack/</b>{`  README · OVERVIEW · research · INSTALL · templates`}</div>
            <p className="afp-hint">Updating the pack later = diff the new bundle, re-copy changed sources, and replace the managed blocks wholesale between their markers. Never overwrite an accumulated <code>docs/docs-index.js</code>.</p>
          </section>
        )}

        {tab === "contents" && (
          <section className="afp-in">
            <div className="afp-stat-row">
              {[["23", "persona lenses"], ["10", "skills"], ["15", "templates"], ["2", "tools supported"]].map(([v, l]) => (
                <div className="afp-stat" key={l}><div className="v">{v}</div><div className="l">{l}</div></div>
              ))}
            </div>

            <p className="afp-sect-t">The reasoning spine</p>
            <div className="afp-grid afp-2" style={{ marginBottom: 26 }}>
              {SPINE.map((s) => {
                const I = s.icon;
                return (<div className="afp-card" key={s.t}><h4><I size={17} className="afp-ico" />{s.t}</h4><p>{s.d}</p></div>);
              })}
            </div>

            <p className="afp-sect-t">The roster — 23 lenses</p>
            <div className="afp-grid afp-2" style={{ marginBottom: 26 }}>
              {ROSTER.map((r) => (
                <div className="afp-card" key={r.g}>
                  <h4><span className="afp-mono" style={{ color: "var(--cyan)" }}>{String(r.n).padStart(2, "0")}</span>{r.g}</h4>
                  <p>{r.d}</p>
                </div>
              ))}
            </div>
            <p className="afp-hint" style={{ marginBottom: 26 }}>Every lens is a uniform card with a convene-when trigger, a severity scale, and a falsifiable veto-clears-when predicate (<code>persona-cards.md</code>). Subject-matter experts beyond these — finance, CFD, clinical — are added per project by <code>/adddomainexperts</code>.</p>

            <p className="afp-sect-t">Files</p>
            <div className="afp-tree">{`ai-forward-pack/
├─ `}<b>README.md</b>{` · `}<b>OVERVIEW.md</b>{` · research-synthesis.md
├─ `}<b>adapters/managed-blocks/</b>{`   ready-to-paste CLAUDE.md / AGENTS.md wiring blocks
├─ `}<b>scripts/docs-graph.py</b>{`     graph mechanics as a tool (derive · flag · freshness — V18)
├─ `}<b>knowledge/</b>{`   18 docs — 11 reasoning (rigor, personas, spike, observability, knowledge-viz, spec standards, UI design, UI archetype grammar + catalog, …) + 7 vendored foundation (BoK, Rules of the Road, Persona Catalog, LOA, Governance, Testing Strategy, C# Style) + FOUNDATION manifest
├─ `}<b>commands/</b>{`    the 10 skills (one SKILL.md each)
├─ `}<b>templates/</b>{`   15 artifact templates (frontmatter headers · glossary · decision note · threat model · privacy review · the Docs Explorer + doc viewer)
├─ `}<b>adapters/</b>{`    INSTALL.md · claude-code/agents · copilot/agents · copilot/prompts
└─ `}<b>examples/</b>{`    finance-repo — a worked /adddomainexperts result`}</div>
          </section>
        )}

        {tab === "skills" && (
          <section className="afp-in">
            <p className="afp-sect-t">The flow</p>
            <div className="afp-flow">
              {FLOW.map((id, i) => {
                const s = SKILLS.find((x) => x.id === id);
                return (
                  <span key={id} style={{ display: "inline-flex", alignItems: "center", gap: 4 }}>
                    <button className={"afp-chip " + s.kind + (open === id ? " on" : "")} onClick={() => { setOpen(id); }}>{s.n}</button>
                    {i < FLOW.length - 1 && <ArrowRight size={14} className="afp-arrow" />}
                  </span>
                );
              })}
            </div>
            <p className="afp-flow-note">+ /investigate whenever a defect appears · dashed = supporting skill · click any skill below</p>

            {SKILLS.map((s) => {
              const isOpen = open === s.id;
              return (
                <div className="afp-skill" key={s.id}>
                  <button className="afp-skill-h" onClick={() => setOpen(isOpen ? null : s.id)}>
                    <span className="afp-skill-name">{s.n}</span>
                    <span className={"afp-tag " + s.kind}>{s.kind}</span>
                    {!isOpen && <span className="afp-skill-when">{s.when}</span>}
                    <span style={{ flex: 1 }} />
                    <ChevronDown size={18} className={"afp-chev" + (isOpen ? " open" : "")} />
                  </button>
                  {isOpen && (
                    <div className="afp-skill-body">
                      <div className="afp-kv"><div className="k">Use it when</div><div className="v">{s.when}</div></div>
                      <div className="afp-kv"><div className="k">You get</div><div className="v">{s.gives}</div></div>
                      <div className="afp-kv"><div className="k">Convened — peers → adversaries</div><div className="v cast">{s.cast}</div></div>
                    </div>
                  )}
                </div>
              );
            })}

            <p className="afp-sect-t" style={{ marginTop: 30 }}>Two rules hold across every skill</p>
            <div>
              <div className="afp-rule"><Sparkles size={16} className="afp-ico" /><span>Each runs the Rigor Protocol scaled to the work's <b>tier</b> — a trivial change gets a quick self-check; a load-bearing one runs all six stages with an external adversary.</span></div>
              <div className="afp-rule"><Shield size={16} className="afp-ico" /><span>Claims carry a <b>confidence label</b>, contracts are <b>verified by execution</b> rather than recalled, and the <b>author never clears its own hard veto.</b></span></div>
            </div>
          </section>
        )}

        {tab === "explore" && (
          <section className="afp-in">
            <p className="afp-sect-t">Explore the knowledge graph</p>
            <p className="afp-hint" style={{ marginTop: 0, marginBottom: 16 }}>The pack is itself a typed graph — standards, skills, veto-holding lenses, tools, and templates, and the relationships between them. Browse it as a <b>hierarchy</b> (grouped by role) or a <b>dynamic graph</b> (the typed relationships). Both drive the same detail panel.</p>

            <div className="afp-kviewtabs">
              <button className={"afp-kviewtab" + (kview === "graph" ? " on" : "")} onClick={() => setKview("graph")}><Network size={14} />Graph</button>
              <button className={"afp-kviewtab" + (kview === "hierarchy" ? " on" : "")} onClick={() => setKview("hierarchy")}><ListTree size={14} />Hierarchy</button>
            </div>

            <div className="afp-kgrid">
              <div className="afp-kleft">
                {kview === "graph"
                  ? <ExploreGraph sel={ksel} setSel={setKsel} focusType={kfocus} setFocusType={setKfocus} />
                  : <ExploreHierarchy sel={ksel} setSel={setKsel} />}
              </div>
              <ExploreDetail sel={ksel} setSel={setKsel} />
            </div>
          </section>
        )}

        <div style={{ marginTop: 34 }}>
          <p className="afp-sect-t">Go deeper</p>
          <div className="afp-deeper">
            {DEEPER.map(([f, d]) => (<div key={f}><span className="f">{f}</span><span className="x">{d}</span></div>))}
          </div>
        </div>

        <footer className="afp-foot">
          <span className="afp-foot-t">Drop it in a repo · honor it on every non-trivial task.</span>
          <DownloadBtn big />
        </footer>
      </div>
    </div>
  );
}
